import { useEffect, useState } from "react";
import NavbarGestionSalas from "../components/NavbarGestionSalas";
import "../styles/EditarEstado.css";
import axios from "axios";

function EditarSala() {
  const [salas, setSalas] = useState([]);
  const [salaSeleccionada, setSalaSeleccionada] = useState(null);
  const [estado, setEstado] = useState("");

  // 🔹 Obtener salas
  useEffect(() => {
    axios.get("http://localhost:3001/salas")
      .then(res => setSalas(res.data))
      .catch(err => console.error(err));
  }, []);

  // 🔹 Seleccionar sala
  const seleccionarSala = (sala) => {
    setSalaSeleccionada(sala);
    setEstado(sala.estado);
  };

  // 🔹 Actualizar estado
  const actualizarEstado = async () => {
    if (!salaSeleccionada) return alert("Selecciona una sala");

    try {
      await axios.put(`http://localhost:3001/salas/${salaSeleccionada.id}`, {
        estado: estado
      });

      alert("Estado actualizado ✅");

      // refrescar lista
      const res = await axios.get("http://localhost:3001/salas");
      setSalas(res.data);

    } catch (error) {
      console.error(error);
      alert("Error al actualizar ❌");
    }
  };

  return (
    <div className="container">
      <NavbarGestionSalas />

      <div className="content">

        {/* IZQUIERDA */}
        <div className="formSection">
          <h2>Sala N° {salaSeleccionada?.id || ""}</h2>

          <div className="formGroup">
            <label>Estado:</label>
            <select
              value={estado}
              onChange={(e) => setEstado(e.target.value)}
            >
              <option value="">Seleccione</option>
              <option value="Disponible">Disponible</option>
              <option value="Ocupada">Ocupada</option>
              <option value="Mantenimiento">Mantenimiento</option>
            </select>
          </div>

          <button className="actualizarBtn" onClick={actualizarEstado}>
            Actualizar
          </button>
        </div>

        {/* DERECHA */}
        <div className="listSection">
          {salas.map((sala) => (
            <div
              key={sala.id}
              className="salaItem"
              onClick={() => seleccionarSala(sala)}
            >
              <p><strong>Sala No° {sala.id}</strong></p>
              <p>Nombre: {sala.nombre}</p>
            </div>
          ))}
        </div>

      </div>

      <div className="footer">
        <button className="nextBtn">→</button>
      </div>
    </div>
  );
}

export default EditarSala;
